class Room {
  constructor(router) {
    this.router = router;
    this.peers = new Map();
  }

  addPeer(id) {
    this.peers.set(id, {
      transports: [],
      producers: [],
      consumers: []
    });
  }

  removePeer(id) {
    this.peers.delete(id);
  }
}

module.exports = Room;


server.js

const express = require("express");
const http = require("http");
const { Server } = require("socket.io");
const mediasoup = require("mediasoup");
const Room = require("./room");

const app = express();
const server = http.createServer(app);

const io = new Server(server, {
  cors: {
    origin: "*"
  }
});

let worker;
let router;
let room;

(async () => {
  worker = await mediasoup.createWorker();

  router = await worker.createRouter({
    mediaCodecs: [
      {
        kind: "audio",
        mimeType: "audio/opus",
        clockRate: 48000,
        channels: 2
      }
    ]
  });

  room = new Room(router);
})();

io.on("connection", socket => {

  room.addPeer(socket.id);

  socket.on("rtpCapabilities", cb => {
    cb(router.rtpCapabilities);
  });

  socket.on("createTransport", async cb => {

    const transport =
      await router.createWebRtcTransport({
        listenIps: [{
          ip: "0.0.0.0",
          announcedIp: "YOUR_PUBLIC_IP"
        }],
        enableUdp: true,
        enableTcp: true
      });

    room.peers
      .get(socket.id)
      .transports.push(transport);

    cb({
      id: transport.id,
      iceParameters:
        transport.iceParameters,
      iceCandidates:
        transport.iceCandidates,
      dtlsParameters:
        transport.dtlsParameters
    });
  });

  socket.on(
    "connectTransport",
    async ({ transportId, dtlsParameters }) => {

      const transport =
        room.peers
          .get(socket.id)
          .transports
          .find(t => t.id === transportId);

      await transport.connect({
        dtlsParameters
      });
    }
  );

  socket.on(
    "produce",
    async (
      {
        transportId,
        kind,
        rtpParameters
      },
      cb
    ) => {

      const transport =
        room.peers
          .get(socket.id)
          .transports
          .find(t => t.id === transportId);

      const producer =
        await transport.produce({
          kind,
          rtpParameters
        });

      room.peers
        .get(socket.id)
        .producers.push(producer);

      cb({
        producerId: producer.id
      });

      socket.broadcast.emit(
        "newProducer",
        producer.id
      );
    }
  );

  socket.on("disconnect", () => {
    room.removePeer(socket.id);
  });
});

server.listen(3000);


