import { useState } from "react";
import { socket } from "./socket";
import { createDevice }
 from "./mediasoup";

function App() {

  const [joined, setJoined] =
    useState(false);

  async function joinRoom() {

    const stream =
      await navigator.mediaDevices
        .getUserMedia({
          audio: true
        });

    const track =
      stream.getAudioTracks()[0];

    const rtpCapabilities =
      await new Promise(resolve => {
        socket.emit(
          "rtpCapabilities",
          resolve
        );
      });

    const device =
      await createDevice(
        rtpCapabilities
      );

    const transportInfo =
      await new Promise(resolve => {
        socket.emit(
          "createTransport",
          resolve
        );
      });

    const transport =
      device.createSendTransport(
        transportInfo
      );

    transport.on(
      "connect",
      async (
        { dtlsParameters },
        callback
      ) => {

        socket.emit(
          "connectTransport",
          {
            transportId:
              transport.id,
            dtlsParameters
          }
        );

        callback();
      }
    );

    transport.on(
      "produce",
      async (
        parameters,
        callback
      ) => {

        socket.emit(
          "produce",
          {
            transportId:
              transport.id,
            kind:
              parameters.kind,
            rtpParameters:
              parameters.rtpParameters
          },
          ({ producerId }) => {

            callback({
              id: producerId
            });
          }
        );
      }
    );

    await transport.produce({
      track
    });

    setJoined(true);
  }

  return (
    <div>

      <h2>
        Voice Room
      </h2>

      {!joined &&
        <button
          onClick={joinRoom}
        >
          Join Room
        </button>
      }

      {joined &&
        <div>
          Connected
        </div>
      }

    </div>
  );
}

export default App;


